import React, { Component } from 'react';

class About extends Component {
    render() {
        return (
            <div className="about-style">
                <h1>About</h1>
                <div className="about-pane-holder">
                    <div className="about-left">
                        <h2>Left</h2>
                    </div>
                    <div className="about-right">
                        <h2>Right</h2>
                    </div>
                </div>
            </div>
        )
    }
}

export default About;
